/// <item><description>not abstract</description></item>
/// <item><description>return type is either <see langword="void" />, <see cref="T:System.Threading.Tasks.Task" />, or <see cref="T:System.Threading.Tasks.ValueTask" />. If <see langword="void" />, then it shouldn't be <see langword="async" />.</description></item>
/// </list>
/// </description>
/// </item>
/// </list>
/// </remarks>
[AttributeUsage(AttributeTargets.Method, Inherited = false)]
public class TestMethodAttribute : Attribute
{
	/// <summary>
	/// Gets or sets display name for the test.
	/// </summary>
	public string? DisplayName { get; set; }

	/// <summary>
